import tiktoken
from functools import lru_cache

@lru_cache(maxsize=8)
def get_encoder(encoding_name: str) -> tiktoken.Encoding:
    return tiktoken.get_encoding(encoding_name)

def estimate_cost(
    prompt: str,
    model: str = "gpt-4",
    price_per_1k_input: float = 0.03,
) -> float:
    """Estimate API cost for a prompt before sending."""
    enc_name = "cl100k_base" if "gpt-4" in model or "gpt-3.5" in model else "p50k_base"
    enc = get_encoder(enc_name)
    n_tokens = len(enc.encode(prompt))
    return n_tokens / 1000 * price_per_1k_input

# Truncate a prompt to fit within a context limit
def truncate_to_tokens(
    text: str,
    max_tokens: int,
    encoding: str = "cl100k_base",
) -> str:
    enc = get_encoder(encoding)
    ids = enc.encode(text)
    if len(ids) <= max_tokens:
        return text
    return enc.decode(ids[:max_tokens])

prompt = "Explain byte-pair encoding in detail with examples."
print(f"Estimated cost: ${estimate_cost(prompt):.5f}")
print(f"Truncated (10 tokens): {truncate_to_tokens(prompt, 10)!r}")
